mapper.select:
/* com.erns.coching.search.mapper.RecommendKeywordDAO.getList */

SELECT 
	ZZ.*
FROM 
	(	
		SELECT

		FROM T_RECOMMEND_KEYWORD AA					






				ORDER BY AA.SORT_ORD ASC


	) ZZ

	OFFSET #{offset} LIMIT #{rowSize}

    	/* com.erns.coching.search.mapper.RecommendKeywordDAO.load */

		SELECT

		FROM T_RECOMMEND_KEYWORD AA

			AND COALESCE(AA.DEL_YN, 'N') = 'N'
			AND AA.SEQ = #{value, jdbcType=INTEGER}

mapper.insert:
	/* com.erns.coching.search.mapper.RecommendKeywordDAO.insert */


	SELECT nextval('seq_t_recommend_keyword')


INSERT INTO T_RECOMMEND_KEYWORD (
	  SEQ
	, NAME
	, USE_YN
	, DEL_YN
	, SORT_ORD
	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM

) VALUES (
	  #{seq							, jdbcType=INTEGER}
	, #{name						, jdbcType=VARCHAR}
	, COALESCE(#{useYn	, jdbcType=VARCHAR}, 'Y')
	, COALESCE(#{delYn	, jdbcType=VARCHAR}, 'N')
	, (SELECT COALESCE(MAX(S.SORT_ORD), 1) FROM T_RECOMMEND_KEYWORD S)
	, #{rgtr						, jdbcType=INTEGER}
	, now() 
	, #{chnr						, jdbcType=INTEGER}
	, now()
)

mapper.update:
    	/* com.erns.coching.search.mapper.RecommendKeywordDAO.update */

		UPDATE T_RECOMMEND_KEYWORD SET
				NAME 				= #{name	, jdbcType=VARCHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND seq		= #{seq	, jdbcType=INTEGER}

    	/* com.erns.coching.search.mapper.RecommendKeywordDAO.updateSortOrder */

		UPDATE T_RECOMMEND_KEYWORD SET
				SORT_ORD 			= #{sortOrd	, jdbcType=INTEGER}			

			AND seq		= #{seq	, jdbcType=INTEGER}

    	/* com.erns.coching.search.mapper.RecommendKeywordDAO.updateUseYn */

		UPDATE T_RECOMMEND_KEYWORD SET
				USE_YN 			= #{useYn	, jdbcType=CHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND seq		= #{seq	, jdbcType=INTEGER}

    	/* com.erns.coching.search.mapper.RecommendKeywordDAO.updateDelYn */

		UPDATE T_RECOMMEND_KEYWORD SET
				DEL_YN 			= #{delYn	, jdbcType=CHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND seq		= #{seq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.search.mapper.RecommendKeywordDAO.delete */

DELETE FROM T_RECOMMEND_KEYWORD

	AND SEQ 	= #{value	, jdbcType=INTEGER}
